SELECT
    ssr.*
FROM sms_seckill_sku_relation ssr
LEFT JOIN sms_seckill_session sss ON ssr.promotion_session_id = sss.id


        ssr.promotion_session_id = #{promotionSessionId}


        AND (


                    ssr.id BETWEEN #{range.start} AND #{range.end}

                OR

                    ssr.sku_id BETWEEN #{range.start} AND #{range.end}

                OR

            sss.name LIKE CONCAT(#{key}, '%')
        )


ORDER BY ssr.id DESC
